import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def get_packages(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            key = f"{pname}::{fw['framework']}"
            for pkg in fw.get('topLevelPackages', []):
                result[(key, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_packages(baseline)
a = get_packages(after)

changes = []
unchanged = []

all_keys = sorted(set(list(b.keys()) + list(a.keys())))
for k in all_keys:
    proj, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv and av and bv == av:
        unchanged.append((proj, pkg, av))
    elif bv and av and bv != av:
        changes.append((proj, pkg, bv, av, "Aligned to highest version"))
    elif bv and not av:
        changes.append((proj, pkg, bv, "-", "Removed"))
    elif not bv and av:
        changes.append((proj, pkg, "-", av, "Added"))

print("=== CHANGES ===")
if changes:
    for c in changes:
        print(f"  {c[0]} | {c[1]} | {c[2]} -> {c[3]} | {c[4]}")
else:
    print("  None")

print(f"\n=== UNCHANGED: {len(unchanged)} packages ===")
for u in unchanged:
    print(f"  {u[0]} | {u[1]} | {u[2]}")
